-- ============================================================================
-- Quiz Seed: Mark — Part 1 (Chapters 1–8)
-- 3 difficulties × 8 chapters = 128 total questions
--   kids:   3 per chapter  = 24
--   teens:  5 per chapter  = 40
--   adults: 8 per chapter  = 64
-- ============================================================================

-- ═══════════════ CHAPTERS 1–4 ═══════════════

-- ═══ Mark Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 1, 'kids', 1, 'Who baptized Jesus in the river Jordan?', 'John the Baptist', 'Peter', 'Moses', 'Paul', 'a', 'Mark 1:9 — "Jesus came from Nazareth of Galilee, and was baptized of John in Jordan."'),
('Mark', 1, 'kids', 2, 'What happened when Jesus came up out of the water?', 'The heavens opened and the Spirit descended like a dove', 'A rainbow appeared', 'Thunder struck the ground', 'The river dried up', 'a', 'Mark 1:10 — "And straightway coming up out of the water, he saw the heavens opened, and the Spirit like a dove descending upon him."'),
('Mark', 1, 'kids', 3, 'What did Jesus tell the fishermen to follow Him and He would make them?', 'Fishers of men', 'Builders of temples', 'Rulers of nations', 'Writers of books', 'a', 'Mark 1:17 — "Come ye after me, and I will make you to become fishers of men."'),
-- Teens
('Mark', 1, 'teens', 1, 'What Old Testament prophet is quoted at the beginning of Mark?', 'Isaiah', 'Jeremiah', 'Ezekiel', 'Daniel', 'a', 'Mark 1:2-3 — "As it is written in the prophets... The voice of one crying in the wilderness, Prepare ye the way of the Lord" (quoting Isaiah 40:3).'),
('Mark', 1, 'teens', 2, 'How long was Jesus tempted in the wilderness?', 'Forty days', 'Seven days', 'Three days', 'Twelve days', 'a', 'Mark 1:13 — "And he was there in the wilderness forty days, tempted of Satan."'),
('Mark', 1, 'teens', 3, 'What was the first thing Jesus preached?', 'The kingdom of God is at hand: repent ye, and believe the gospel', 'Beware the scribes and Pharisees', 'Love your enemies', 'Blessed are the poor in spirit', 'a', 'Mark 1:15 — "The time is fulfilled, and the kingdom of God is at hand: repent ye, and believe the gospel."'),
('Mark', 1, 'teens', 4, 'What did the unclean spirit say to Jesus in the synagogue at Capernaum?', 'I know thee who thou art, the Holy One of God', 'We do not know you', 'Leave us alone forever', 'You have no power here', 'a', 'Mark 1:24 — "I know thee who thou art, the Holy One of God."'),
('Mark', 1, 'teens', 5, 'What did Jesus do very early in the morning after healing many people?', 'Rose up a great while before day and went to a solitary place to pray', 'Slept until noon', 'Traveled to Jerusalem', 'Called a large meeting', 'a', 'Mark 1:35 — "And in the morning, rising up a great while before day, he went out, and departed into a solitary place, and there prayed."'),
-- Adults
('Mark', 1, 'adults', 1, 'What is the very first verse of Mark''s Gospel?', 'The beginning of the gospel of Jesus Christ, the Son of God', 'In the beginning was the Word', 'The book of the generation of Jesus Christ', 'Forasmuch as many have taken in hand', 'a', 'Mark 1:1 — "The beginning of the gospel of Jesus Christ, the Son of God."'),
('Mark', 1, 'adults', 2, 'What did John the Baptist wear and eat according to Mark?', 'Camel''s hair with a leather girdle; locusts and wild honey', 'Fine linen and bread', 'Wool and fish', 'Sackcloth and figs', 'a', 'Mark 1:6 — "And John was clothed with camel''s hair, and with a girdle of a skin about his loins; and he did eat locusts and wild honey."'),
('Mark', 1, 'adults', 3, 'What voice spoke from heaven at Jesus'' baptism and what did it say?', 'Thou art my beloved Son, in whom I am well pleased', 'This is a great prophet, listen to him', 'Behold the Lamb of God', 'Go and sin no more', 'a', 'Mark 1:11 — "And there came a voice from heaven, saying, Thou art my beloved Son, in whom I am well pleased."'),
('Mark', 1, 'adults', 4, 'Which two sets of brothers did Jesus call as His first four disciples?', 'Simon and Andrew, then James and John (sons of Zebedee)', 'Philip and Bartholomew, then Thomas and Matthew', 'James and Judas, then Peter and Andrew', 'Matthew and Thomas, then Philip and Nathanael', 'a', 'Mark 1:16-20 — Simon and Andrew casting a net, then James and John mending their nets.'),
('Mark', 1, 'adults', 5, 'What did Jesus command the unclean spirit, and what happened?', 'He rebuked him saying "Hold thy peace, and come out of him," and the spirit came out with convulsions and a loud cry', 'He touched the man and the spirit vanished silently', 'He prayed over the man for many hours', 'He sent the man to the priests for cleansing', 'a', 'Mark 1:25-26 — "Jesus rebuked him, saying, Hold thy peace, and come out of him. And when the unclean spirit had torn him, and cried with a loud voice, he came out of him."'),
('Mark', 1, 'adults', 6, 'Whom did Jesus heal in Simon''s house, and how?', 'Simon''s wife''s mother, sick of a fever; He took her by the hand and lifted her up', 'Simon''s daughter who was lame; He spoke a word', 'Simon''s servant who was blind; He touched his eyes', 'Simon''s brother who had leprosy; He commanded him to wash', 'a', 'Mark 1:30-31 — "But Simon''s wife''s mother lay sick of a fever... and he came and took her by the hand, and lifted her up; and immediately the fever left her."'),
('Mark', 1, 'adults', 7, 'What did Jesus tell the cleansed leper NOT to do, and what did the leper do?', 'Jesus charged him to say nothing, but the man published it much and blazed abroad the matter', 'Jesus told him not to return home, but he went home immediately', 'Jesus told him to stay in the city, but he fled to the wilderness', 'Jesus told him to go to Jerusalem, but he went to Samaria', 'a', 'Mark 1:44-45 — "See thou say nothing to any man... But he went out, and began to publish it much, and to blaze abroad the matter."'),
('Mark', 1, 'adults', 8, 'What theological significance does Mark''s use of "straightway" (euthys) throughout chapter 1 convey?', 'It emphasizes the urgency and immediate authority of Jesus'' ministry as the active Servant of God', 'It shows that Mark was writing in a hurry', 'It indicates the events happened on a single day', 'It suggests Mark had poor literary style', 'a', 'Mark uses "straightway/immediately" over 40 times in his Gospel, emphasizing Christ''s decisive action — especially prominent in chapter 1 (vv. 10, 12, 18, 20, 21, 23, 28, 29, 30, 42).');

-- ═══ Mark Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 2, 'kids', 1, 'How did the sick man''s friends get him to Jesus?', 'They lowered him through the roof on his bed', 'They carried him through the front door', 'They waited outside until Jesus came out', 'They called Jesus on a phone', 'a', 'Mark 2:4 — "They uncovered the roof where he was: and when they had broken it up, they let down the bed wherein the sick of the palsy lay."'),
('Mark', 2, 'kids', 2, 'What did Jesus tell the sick man to do?', 'Arise, take up thy bed, and walk', 'Stay in bed and rest', 'Go to the doctors', 'Wait until tomorrow', 'a', 'Mark 2:11 — "I say unto thee, Arise, and take up thy bed, and go thy way into thine house."'),
('Mark', 2, 'kids', 3, 'Who did Jesus call to follow Him from the tax collector''s table?', 'Levi (Matthew)', 'Simon Peter', 'James', 'John', 'a', 'Mark 2:14 — "And as he passed by, he saw Levi the son of Alphaeus sitting at the receipt of custom, and said unto him, Follow me."'),
-- Teens
('Mark', 2, 'teens', 1, 'What did Jesus say first to the paralyzed man, and why did the scribes object?', 'He said "Thy sins be forgiven thee," and the scribes said only God can forgive sins', 'He said "Stand up and walk," and the scribes said he broke the Sabbath', 'He said "Your faith has saved you," and the scribes questioned his authority', 'He said "Be healed," and the scribes doubted his power', 'a', 'Mark 2:5,7 — "Son, thy sins be forgiven thee... Why doth this man thus speak blasphemies? who can forgive sins but God only?"'),
('Mark', 2, 'teens', 2, 'Why did the Pharisees criticize Jesus for eating with publicans and sinners?', 'They believed a righteous teacher should not associate with sinful people', 'They were concerned about food safety', 'They wanted a private dinner invitation', 'They objected to the type of food served', 'a', 'Mark 2:16 — "How is it that he eateth and drinketh with publicans and sinners?"'),
('Mark', 2, 'teens', 3, 'How did Jesus respond to the criticism about eating with sinners?', 'They that are whole have no need of the physician, but they that are sick', 'He apologized and left the table', 'He ignored them completely', 'He told the sinners to leave', 'a', 'Mark 2:17 — "They that are whole have no need of the physician, but they that are sick: I came not to call the righteous, but sinners to repentance."'),
('Mark', 2, 'teens', 4, 'What illustration did Jesus use about new wine?', 'New wine must be put into new bottles (wineskins)', 'New wine should be poured onto the ground', 'New wine must be mixed with old wine', 'New wine should be stored in clay pots', 'a', 'Mark 2:22 — "And no man putteth new wine into old bottles... but new wine must be put into new bottles."'),
('Mark', 2, 'teens', 5, 'What did Jesus say about the Sabbath in response to the Pharisees?', 'The sabbath was made for man, and not man for the sabbath', 'The sabbath should be abolished', 'The sabbath rules must be made stricter', 'The sabbath only applies to priests', 'a', 'Mark 2:27 — "The sabbath was made for man, and not man for the sabbath."'),
-- Adults
('Mark', 2, 'adults', 1, 'What does Jesus'' statement "Son, thy sins be forgiven thee" reveal about the relationship between sin and sickness?', 'Jesus addresses the root spiritual need before the physical, demonstrating His divine authority to forgive sins', 'That all sickness is directly caused by personal sin', 'That physical healing is unimportant', 'That forgiveness requires a temple sacrifice', 'a', 'Mark 2:5 — "Son, thy sins be forgiven thee." Jesus prioritizes the man''s spiritual condition, then heals physically to prove His authority (v. 10).'),
('Mark', 2, 'adults', 2, 'What reasoning did Jesus use to prove He had power to forgive sins?', 'Whether is it easier to say, Thy sins be forgiven; or to say, Arise and walk? — then He healed the man as visible proof', 'He quoted an Old Testament prophecy', 'He called angels to testify', 'He asked the Pharisees to verify His identity', 'a', 'Mark 2:9-11 — "Whether is it easier to say to the sick of the palsy, Thy sins be forgiven thee; or to say, Arise, and take up thy bed, and walk? But that ye may know that the Son of man hath power on earth to forgive sins..."'),
('Mark', 2, 'adults', 3, 'What title does Jesus use for Himself in verse 10, and what does it signify?', 'The Son of man — a Messianic title from Daniel 7:13 indicating both divine authority and human identification', 'The Son of David — referring only to His royal lineage', 'The Son of God — emphasizing only His deity', 'The Lamb of God — pointing to His sacrifice', 'a', 'Mark 2:10 — "That ye may know that the Son of man hath power on earth to forgive sins." "Son of man" echoes Daniel 7:13-14.'),
('Mark', 2, 'adults', 4, 'What Old Testament example did Jesus cite when defending His disciples for plucking grain on the Sabbath?', 'David eating the shewbread in the house of God when Abiathar was high priest', 'Moses gathering manna on the Sabbath', 'Elijah being fed by ravens', 'Joshua marching around Jericho on the Sabbath', 'a', 'Mark 2:25-26 — "Have ye never read what David did... how he went into the house of God in the days of Abiathar the high priest, and did eat the shewbread."'),
('Mark', 2, 'adults', 5, 'What does Jesus claim about Himself in Mark 2:28?', 'The Son of man is Lord also of the sabbath', 'The sabbath belongs to the Pharisees', 'Only priests have authority over the sabbath', 'The sabbath is no longer relevant', 'a', 'Mark 2:28 — "Therefore the Son of man is Lord also of the sabbath."'),
('Mark', 2, 'adults', 6, 'What do the parables of the unshrunk cloth and new wine teach about Jesus'' ministry?', 'Christ''s new covenant cannot simply be patched onto old legalistic traditions; it requires a new framework', 'Old traditions are always better than new ones', 'Wine making was an important first-century industry', 'Clothing repair was a common occupation', 'a', 'Mark 2:21-22 — The new cloth and new wine illustrations show that Jesus'' teaching is not merely a reform of Pharisaic Judaism but something entirely new.'),
('Mark', 2, 'adults', 7, 'How does the calling of Levi illustrate the nature of Jesus'' ministry?', 'It shows Jesus deliberately chose a despised tax collector, demonstrating that His kingdom includes social outcasts', 'It shows Jesus needed wealthy supporters', 'It demonstrates that tax collectors were respected', 'It proves that all vocations are equally moral', 'a', 'Mark 2:14-15 — Jesus called Levi the publican and ate at his house with many sinners, scandalizing the religious establishment.'),
('Mark', 2, 'adults', 8, 'What does the reaction of the crowd in verse 12 — "We never saw it on this fashion" — indicate about the healing?', 'It was an unprecedented display of divine power that amazed all, including skeptics, and glorified God', 'The crowd was simply entertained', 'They had never seen a paralyzed man before', 'They were frightened and wanted to flee', 'a', 'Mark 2:12 — "Insomuch that they were all amazed, and glorified God, saying, We never saw it on this fashion."');

-- ═══ Mark Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 3, 'kids', 1, 'What was wrong with the man''s hand in the synagogue?', 'It was withered (dried up)', 'It was cut off', 'It was too big', 'It was burned', 'a', 'Mark 3:1 — "And there was a man there which had a withered hand."'),
('Mark', 3, 'kids', 2, 'How many special helpers (apostles) did Jesus choose?', 'Twelve', 'Seven', 'Three', 'Twenty', 'a', 'Mark 3:14 — "And he ordained twelve, that they should be with him."'),
('Mark', 3, 'kids', 3, 'Who did Jesus say are His brother, sister, and mother?', 'Whoever does the will of God', 'Only His relatives', 'Only the twelve disciples', 'Only people in the synagogue', 'a', 'Mark 3:35 — "For whosoever shall do the will of God, the same is my brother, and my sister, and mother."'),
-- Teens
('Mark', 3, 'teens', 1, 'Why were the Pharisees watching Jesus in the synagogue on the Sabbath?', 'To see if He would heal on the sabbath so they could accuse Him', 'To learn from His teaching', 'To invite Him to a feast', 'To ask Him questions about Moses', 'a', 'Mark 3:2 — "And they watched him, whether he would heal him on the sabbath day; that they might accuse him."'),
('Mark', 3, 'teens', 2, 'How did Jesus feel when He looked at the Pharisees before healing the man?', 'He looked on them with anger, grieved at the hardness of their hearts', 'He was indifferent to them', 'He was amused by their questions', 'He was frightened by their power', 'a', 'Mark 3:5 — "And when he had looked round about on them with anger, being grieved for the hardness of their hearts."'),
('Mark', 3, 'teens', 3, 'Who did the Pharisees join with to plot against Jesus?', 'The Herodians', 'The Sadducees', 'The Romans', 'The Essenes', 'a', 'Mark 3:6 — "And the Pharisees went forth, and straightway took counsel with the Herodians against him, how they might destroy him."'),
('Mark', 3, 'teens', 4, 'What two purposes did Jesus ordain the twelve apostles for?', 'To be with Him, and to be sent out to preach with power to heal and cast out devils', 'To guard the temple and collect tithes', 'To write the Old Testament and teach children', 'To serve in the Roman government and spread news', 'a', 'Mark 3:14-15 — "He ordained twelve, that they should be with him, and that he might send them forth to preach, And to have power to heal sicknesses, and to cast out devils."'),
('Mark', 3, 'teens', 5, 'What unforgivable sin did Jesus warn about?', 'Blasphemy against the Holy Ghost', 'Missing a day of worship', 'Eating unclean food', 'Working on the sabbath', 'a', 'Mark 3:29 — "But he that shall blaspheme against the Holy Ghost hath never forgiveness, but is in danger of eternal damnation."'),
-- Adults
('Mark', 3, 'adults', 1, 'What question did Jesus ask in the synagogue before healing the withered hand?', 'Is it lawful to do good on the sabbath days, or to do evil? to save life, or to kill?', 'Is it lawful to eat on the sabbath?', 'Is it lawful to walk on the sabbath?', 'Is it lawful to pray on the sabbath?', 'a', 'Mark 3:4 — "Is it lawful to do good on the sabbath days, or to do evil? to save life, or to kill? But they held their peace."'),
('Mark', 3, 'adults', 2, 'What does Mark record about the unclean spirits'' response when they saw Jesus?', 'They fell down before Him and cried, Thou art the Son of God', 'They fled without speaking', 'They challenged Him to prove His identity', 'They ignored Him completely', 'a', 'Mark 3:11 — "And unclean spirits, when they saw him, fell down before him, and cried, saying, Thou art the Son of God."'),
('Mark', 3, 'adults', 3, 'What surname did Jesus give to James and John, and what does it mean?', 'Boanerges, which is The sons of thunder', 'Cephas, which is A stone', 'Didymus, which is A twin', 'Iscariot, which is Man of Kerioth', 'a', 'Mark 3:17 — "And James the son of Zebedee, and John the brother of James; and he surnamed them Boanerges, which is, The sons of thunder."'),
('Mark', 3, 'adults', 4, 'What did the scribes from Jerusalem accuse Jesus of?', 'Having Beelzebub and casting out devils by the prince of the devils', 'Being a drunkard and a glutton', 'Stealing from the temple treasury', 'Practicing Egyptian sorcery', 'a', 'Mark 3:22 — "And the scribes which came down from Jerusalem said, He hath Beelzebub, and by the prince of the devils casteth he out devils."'),
('Mark', 3, 'adults', 5, 'How did Jesus refute the accusation that He cast out demons by Satan''s power?', 'A kingdom divided against itself cannot stand; Satan would not cast out his own forces', 'He performed an even greater miracle', 'He quoted a passage from Leviticus', 'He called witnesses to testify', 'a', 'Mark 3:23-26 — "How can Satan cast out Satan? And if a kingdom be divided against itself, that kingdom cannot stand."'),
('Mark', 3, 'adults', 6, 'What parable does Jesus use about the "strong man" in verse 27?', 'No man can enter a strong man''s house and spoil his goods unless he first bind the strong man', 'A strong man builds his house on rock', 'A strong man lifts heavy burdens for others', 'A strong man guards the city gates', 'a', 'Mark 3:27 — "No man can enter into a strong man''s house, and spoil his goods, except he will first bind the strong man; and then he will spoil his house."'),
('Mark', 3, 'adults', 7, 'Why specifically did Jesus say the scribes were guilty of blaspheming the Holy Ghost?', 'Because they said He had an unclean spirit — attributing the Spirit''s work to Satan', 'Because they refused to attend the synagogue', 'Because they did not fast on the appointed days', 'Because they collected taxes for Rome', 'a', 'Mark 3:30 — "Because they said, He hath an unclean spirit." They attributed the Holy Spirit''s miraculous work through Christ to demonic power.'),
('Mark', 3, 'adults', 8, 'What does Jesus'' redefinition of family in verses 33-35 teach about the nature of the kingdom of God?', 'Spiritual kinship through obedience to God''s will transcends and supersedes biological family ties', 'Biological family is unimportant in every situation', 'Only celibate people can be part of God''s family', 'Family relationships are meaningless in the afterlife', 'a', 'Mark 3:33-35 — "Who is my mother, or my brethren?... For whosoever shall do the will of God, the same is my brother, and my sister, and mother."');

-- ═══ Mark Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 4, 'kids', 1, 'In Jesus'' story, what happened to the seed that fell on good ground?', 'It grew and brought forth fruit, some thirty, sixty, and a hundredfold', 'It died right away', 'It turned into a tree', 'It was eaten by birds', 'a', 'Mark 4:8 — "And other fell on good ground, and did yield fruit that sprang up and increased; and brought forth, some thirty, and some sixty, and some an hundred."'),
('Mark', 4, 'kids', 2, 'What was Jesus doing in the boat during the storm?', 'Sleeping on a pillow', 'Fishing', 'Rowing', 'Standing and watching', 'a', 'Mark 4:38 — "And he was in the hinder part of the ship, asleep on a pillow."'),
('Mark', 4, 'kids', 3, 'What did Jesus say to make the storm stop?', 'Peace, be still', 'Stop, wind', 'Go away, storm', 'Calm down, waves', 'a', 'Mark 4:39 — "And he arose, and rebuked the wind, and said unto the sea, Peace, be still. And the wind ceased, and there was a great calm."'),
-- Teens
('Mark', 4, 'teens', 1, 'In the parable of the sower, what do the thorns represent?', 'The cares of this world, the deceitfulness of riches, and the lusts of other things', 'Evil people who attack believers', 'Diseases and sickness', 'Government persecution', 'a', 'Mark 4:19 — "And the cares of this world, and the deceitfulness of riches, and the lusts of other things entering in, choke the word, and it becometh unfruitful."'),
('Mark', 4, 'teens', 2, 'What did Jesus say about hidden things in verse 22?', 'There is nothing hid which shall not be manifested, nor kept secret but that it shall come abroad', 'Some secrets will remain forever hidden', 'Only God knows all hidden things', 'Hidden things are always sinful', 'a', 'Mark 4:22 — "For there is nothing hid, which shall not be manifested; neither was any thing kept secret, but that it should come abroad."'),
('Mark', 4, 'teens', 3, 'What is the mustard seed parable about?', 'The kingdom of God starts very small but grows to become the greatest', 'Mustard is the best seasoning', 'Small seeds are worthless', 'Only large trees please God', 'a', 'Mark 4:31-32 — "When it is sown in the earth, is less than all the seeds... But when it is sown, it groweth up, and becometh greater than all herbs."'),
('Mark', 4, 'teens', 4, 'What did the disciples say to Jesus during the storm?', 'Master, carest thou not that we perish?', 'Lord, save us, we are drowning', 'Teacher, help us row to shore', 'Rabbi, send the wind away', 'a', 'Mark 4:38 — "And they awake him, and say unto him, Master, carest thou not that we perish?"'),
('Mark', 4, 'teens', 5, 'What question did the disciples ask each other after the storm was calmed?', 'What manner of man is this, that even the wind and the sea obey him?', 'How did he learn to control weather?', 'Should we tell people about this?', 'Was that just a coincidence?', 'a', 'Mark 4:41 — "And they feared exceedingly, and said one to another, What manner of man is this, that even the wind and the sea obey him?"'),
-- Adults
('Mark', 4, 'adults', 1, 'In the parable of the sower, what does the seed that fell by the way side represent?', 'Those who hear the word but Satan immediately takes it away', 'Those who hear and believe permanently', 'Those who never hear the word', 'Those who spread the word to others', 'a', 'Mark 4:15 — "And these are they by the way side, where the word is sown; but when they have heard, Satan cometh immediately, and taketh away the word."'),
('Mark', 4, 'adults', 2, 'What does Jesus explain about why He speaks in parables?', 'That seeing they may see, and not perceive; and hearing they may hear, and not understand — fulfilling Isaiah''s prophecy', 'To make His teachings easier to understand', 'To entertain the crowd', 'To avoid controversy', 'a', 'Mark 4:12 — "That seeing they may see, and not perceive; and hearing they may hear, and not understand; lest at any time they should be converted, and their sins should be forgiven them."'),
('Mark', 4, 'adults', 3, 'What does the stony ground represent in the parable of the sower?', 'Those who receive the word gladly but have no root and fall away when affliction or persecution arises', 'Those who never hear the gospel', 'Those who bear abundant fruit', 'Those who deliberately reject the truth', 'a', 'Mark 4:16-17 — "These are they... which, when they have heard the word, immediately receive it with gladness; And have no root... when affliction or persecution ariseth for the word''s sake, immediately they are offended."'),
('Mark', 4, 'adults', 4, 'What principle does Jesus state in verse 24 about measure?', 'With what measure ye mete, it shall be measured to you: and unto you that hear shall more be given', 'Only the wealthy will receive from God', 'Everyone receives the same regardless', 'God does not measure our deeds', 'a', 'Mark 4:24 — "With what measure ye mete, it shall be measured to you: and unto you that hear shall more be given."'),
('Mark', 4, 'adults', 5, 'In the parable of the seed growing secretly (Mark 4:26-29), what is the main point?', 'The kingdom of God grows by divine power, not human effort — the earth bringeth forth fruit of herself', 'Farmers should sleep more and work less', 'Agriculture is the most godly profession', 'Seeds are a symbol of money', 'a', 'Mark 4:27-28 — "And should sleep, and rise night and day, and the seed should spring and grow up, he knoweth not how. For the earth bringeth forth fruit of herself."'),
('Mark', 4, 'adults', 6, 'What does Jesus'' rebuke "Why are ye so fearful? how is it that ye have no faith?" reveal?', 'That faith and fear are incompatible — the disciples should have trusted Christ''s presence even in the storm', 'That storms are illusions', 'That the disciples were cowards', 'That Jesus expected them to calm the storm themselves', 'a', 'Mark 4:40 — "And he said unto them, Why are ye so fearful? how is it that ye have no faith?"'),
('Mark', 4, 'adults', 7, 'What does the calming of the storm demonstrate about Christ''s nature?', 'His divine sovereignty over creation, since only God commands wind and sea (cf. Psalm 107:29)', 'He had learned weather control from the Essenes', 'He was merely lucky with the timing', 'He used a natural phenomenon', 'a', 'Mark 4:39,41 — "Peace, be still... What manner of man is this, that even the wind and the sea obey him?" This parallels Psalm 107:29 — "He maketh the storm a calm."'),
('Mark', 4, 'adults', 8, 'What literary function does Mark 4:33-34 serve regarding Jesus'' teaching method?', 'It summarizes that Jesus used many parables publicly but explained all things privately to His disciples, showing two levels of revelation', 'It proves Jesus told only one parable', 'It shows Jesus refused to teach the crowds', 'It indicates the disciples never understood', 'a', 'Mark 4:33-34 — "And with many such parables spake he the word unto them, as they were able to hear it. But without a parable spake he not unto them: and when they were alone, he expounded all things to his disciples."');

-- ═══════════════ CHAPTERS 5–8 ═══════════════

-- ═══ Mark Chapter 5 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 5, 'kids', 1, 'Where did the demons go when Jesus cast them out of the man?', 'Into a herd of pigs that ran into the sea', 'Into the mountains', 'Into the temple', 'Into the sky', 'a', 'Mark 5:13 — "And the unclean spirits went out, and entered into the swine: and the herd ran violently down a steep place into the sea."'),
('Mark', 5, 'kids', 2, 'What happened when the sick woman touched Jesus'' clothes?', 'She was healed immediately', 'Nothing happened', 'She fell asleep', 'She became more sick', 'a', 'Mark 5:29 — "And straightway the fountain of her blood was dried up; and she felt in her body that she was healed of that plague."'),
('Mark', 5, 'kids', 3, 'What did Jesus say to the little girl who had died?', 'Talitha cumi, which means Little girl, I say unto thee, arise', 'Go to sleep, child', 'Rest in peace', 'Wake up tomorrow', 'a', 'Mark 5:41 — "And he took the damsel by the hand, and said unto her, Talitha cumi; which is, being interpreted, Damsel, I say unto thee, arise."'),
-- Teens
('Mark', 5, 'teens', 1, 'What was the name the demon-possessed man gave when Jesus asked?', 'Legion, because they were many', 'Beelzebub', 'Satan', 'Destroyer', 'a', 'Mark 5:9 — "And he asked him, What is thy name? And he answered, saying, My name is Legion: for we are many."'),
('Mark', 5, 'teens', 2, 'What did the people of the region ask Jesus to do after He healed the man?', 'They asked Him to depart out of their coasts', 'They threw a feast for Him', 'They asked Him to stay forever', 'They worshipped Him publicly', 'a', 'Mark 5:17 — "And they began to pray him to depart out of their coasts."'),
('Mark', 5, 'teens', 3, 'What did Jesus tell the healed man to do?', 'Go home to thy friends and tell them how great things the Lord hath done for thee', 'Come and follow Me as a disciple', 'Go to the temple and offer a sacrifice', 'Stay silent about what happened', 'a', 'Mark 5:19 — "Go home to thy friends, and tell them how great things the Lord hath done for thee, and hath had compassion on thee."'),
('Mark', 5, 'teens', 4, 'Who came to Jesus begging Him to heal his dying daughter?', 'Jairus, a ruler of the synagogue', 'Nicodemus, a Pharisee', 'Joseph of Arimathea', 'A Roman centurion', 'a', 'Mark 5:22-23 — "And, behold, there cometh one of the rulers of the synagogue, Jairus by name... and besought him greatly, saying, My little daughter lieth at the point of death."'),
('Mark', 5, 'teens', 5, 'What did Jesus say to Jairus when told his daughter was dead?', 'Be not afraid, only believe', 'It is too late now', 'We should turn back', 'Let us pray for her soul', 'a', 'Mark 5:36 — "As soon as Jesus heard the word that was spoken, he saith unto the ruler of the synagogue, Be not afraid, only believe."'),
-- Adults
('Mark', 5, 'adults', 1, 'How does Mark describe the demon-possessed man of the Gadarenes before Jesus healed him?', 'He lived among the tombs, could not be bound even with chains, and cut himself with stones night and day', 'He lived in a fine house and appeared normal', 'He was mute and could not speak', 'He was blind and deaf from birth', 'a', 'Mark 5:3-5 — "Who had his dwelling among the tombs; and no man could bind him, no, not with chains... always, night and day, he was in the mountains, and in the tombs, crying, and cutting himself with stones."'),
('Mark', 5, 'adults', 2, 'How many swine perished when the demons entered them?', 'About two thousand', 'About five hundred', 'About one hundred', 'About ten thousand', 'a', 'Mark 5:13 — "And the unclean spirits went out, and entered into the swine: and the herd ran violently down a steep place into the sea, (they were about two thousand;) and were choked in the sea."'),
('Mark', 5, 'adults', 3, 'What did Jesus perceive when the woman with the issue of blood touched Him?', 'That virtue (power) had gone out of Him', 'That someone had stolen from Him', 'That the crowd was too large', 'That a sinner was nearby', 'a', 'Mark 5:30 — "And Jesus, immediately knowing in himself that virtue had gone out of him, turned him about in the press, and said, Who touched my clothes?"'),
('Mark', 5, 'adults', 4, 'How long had the woman suffered with her issue of blood?', 'Twelve years', 'Seven years', 'Three years', 'Twenty years', 'a', 'Mark 5:25 — "And a certain woman, which had an issue of blood twelve years."'),
('Mark', 5, 'adults', 5, 'What did Jesus say to the woman that identified the true cause of her healing?', 'Thy faith hath made thee whole; go in peace, and be whole of thy plague', 'My power has healed you', 'Your touch has magical properties', 'The garment itself healed you', 'a', 'Mark 5:34 — "Daughter, thy faith hath made thee whole; go in peace, and be whole of thy plague."'),
('Mark', 5, 'adults', 6, 'What was the response of the mourners when Jesus said the girl was not dead but sleeping?', 'They laughed Him to scorn', 'They believed Him immediately', 'They fell on their knees', 'They ran away in fear', 'a', 'Mark 5:40 — "And they laughed him to scorn. But when he had put them all out, he taketh the father and the mother of the damsel, and them that were with him, and entereth in where the damsel was lying."'),
('Mark', 5, 'adults', 7, 'Who did Jesus allow to witness the raising of Jairus'' daughter?', 'Peter, James, and John, along with the father and mother', 'All twelve disciples', 'The entire crowd', 'Only the mother', 'a', 'Mark 5:37,40 — "He suffered no man to follow him, save Peter, and James, and John the brother of James... he taketh the father and the mother of the damsel, and them that were with him."'),
('Mark', 5, 'adults', 8, 'What does the juxtaposition of the woman healed after 12 years of suffering and the 12-year-old girl raised from the dead suggest theologically?', 'Both accounts demonstrate that Jesus has absolute authority over chronic disease and death, with faith as the common thread connecting both miracles', 'The number 12 is merely a coincidence', 'Only women and girls can receive miracles', 'Physical touch is required for all healings', 'a', 'Mark 5:25,42 — The woman suffered 12 years; the girl was 12 years old. Both are restored by Jesus'' power, responding to faith (Jairus'' in v. 36, the woman''s in v. 34).');

-- ═══ Mark Chapter 6 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 6, 'kids', 1, 'Why couldn''t Jesus do many mighty works in His hometown?', 'Because of their unbelief', 'Because He was tired', 'Because it was the sabbath', 'Because He forgot how', 'a', 'Mark 6:5-6 — "And he could there do no mighty work... And he marvelled because of their unbelief."'),
('Mark', 6, 'kids', 2, 'How many people did Jesus feed with five loaves and two fishes?', 'Five thousand men', 'One hundred men', 'Twelve men', 'Fifty men', 'a', 'Mark 6:44 — "And they that did eat of the loaves were about five thousand men."'),
('Mark', 6, 'kids', 3, 'What amazing thing did Jesus do on the sea?', 'He walked on the water', 'He swam very fast', 'He rode a boat alone', 'He caught a big fish', 'a', 'Mark 6:48 — "And he saw them toiling in rowing... and about the fourth watch of the night he cometh unto them, walking upon the sea."'),
-- Teens
('Mark', 6, 'teens', 1, 'What did Jesus tell the twelve to take with them when He sent them out?', 'Nothing except a staff — no bread, no bag, no money, but to wear sandals', 'Plenty of food and money', 'Extra clothing and supplies', 'Weapons for protection', 'a', 'Mark 6:8-9 — "And commanded them that they should take nothing for their journey, save a staff only; no scrip, no bread, no money in their purse: But be shod with sandals."'),
('Mark', 6, 'teens', 2, 'Who had John the Baptist beheaded?', 'Herod, at the request of Herodias'' daughter', 'Pontius Pilate', 'The Sanhedrin', 'A Roman soldier', 'a', 'Mark 6:27 — "And immediately the king sent an executioner, and commanded his head to be brought."'),
('Mark', 6, 'teens', 3, 'Why did Herod fear John the Baptist?', 'He knew John was a just and holy man', 'He thought John had a large army', 'He believed John was a Roman spy', 'He was afraid of John''s magical powers', 'a', 'Mark 6:20 — "For Herod feared John, knowing that he was a just man and an holy."'),
('Mark', 6, 'teens', 4, 'How many baskets of leftovers were collected after the feeding of the five thousand?', 'Twelve baskets full', 'Two baskets full', 'Five baskets full', 'Seven baskets full', 'a', 'Mark 6:43 — "And they took up twelve baskets full of the fragments, and of the fishes."'),
('Mark', 6, 'teens', 5, 'What did the disciples think when they saw Jesus walking on the water?', 'They supposed it was a spirit and cried out in fear', 'They recognized Him immediately', 'They thought it was a fisherman', 'They ignored it and kept rowing', 'a', 'Mark 6:49 — "But when they saw him walking upon the sea, they supposed it had been a spirit, and cried out."'),
-- Adults
('Mark', 6, 'adults', 1, 'What did the people of Nazareth call Jesus, and why did they take offense?', 'The carpenter and son of Mary — they were offended because He was a local tradesman they thought they knew', 'The prophet from Galilee — they expected miracles', 'The teacher from Jerusalem — they questioned His credentials', 'The healer from Bethsaida — they doubted His origins', 'a', 'Mark 6:3 — "Is not this the carpenter, the son of Mary... And they were offended at him."'),
('Mark', 6, 'adults', 2, 'What proverbial saying did Jesus use about His rejection in Nazareth?', 'A prophet is not without honour, but in his own country, and among his own kin, and in his own house', 'No man can serve two masters', 'The last shall be first', 'Where your treasure is, there will your heart be', 'a', 'Mark 6:4 — "A prophet is not without honour, but in his own country, and among his own kin, and in his own house."'),
('Mark', 6, 'adults', 3, 'What did Herod think about Jesus after hearing of His fame?', 'That John the Baptist was risen from the dead', 'That a new prophet had appeared', 'That Moses had returned', 'That Elijah had come back', 'a', 'Mark 6:14,16 — "And king Herod heard of him... But when Herod heard thereof, he said, It is John, whom I beheaded: he is risen from the dead."'),
('Mark', 6, 'adults', 4, 'Why did Herodias want John the Baptist killed?', 'Because John told Herod it was not lawful to have his brother''s wife', 'Because John refused to bow to Herod', 'Because John predicted Herod''s downfall', 'Because John threatened to expose tax fraud', 'a', 'Mark 6:18-19 — "For John had said unto Herod, It is not lawful for thee to have thy brother''s wife. Therefore Herodias had a quarrel against him, and would have killed him."'),
('Mark', 6, 'adults', 5, 'What emotion did Jesus feel when He saw the great multitude before the feeding miracle?', 'Compassion, because they were as sheep not having a shepherd', 'Frustration because they followed Him', 'Anger at their spiritual ignorance', 'Indifference to their physical needs', 'a', 'Mark 6:34 — "And Jesus, when he came out, saw much people, and was moved with compassion toward them, because they were as sheep not having a shepherd."'),
('Mark', 6, 'adults', 6, 'What does Jesus'' command to the disciples — "Give ye them to eat" — reveal about His teaching method?', 'He tested their faith and resourcefulness before demonstrating divine provision, inviting them to participate in the miracle', 'He expected them to buy food from a nearby town', 'He was testing their knowledge of Scripture', 'He was being sarcastic', 'a', 'Mark 6:37 — "Give ye them to eat." Jesus involved the disciples in the miracle, using what they had (5 loaves, 2 fish) to display divine abundance.'),
('Mark', 6, 'adults', 7, 'What does Mark 6:48 say Jesus intended to do when walking on the sea?', 'He would have passed by them — an allusion to Old Testament theophanies (cf. Exodus 33:19, 1 Kings 19:11)', 'He intended to walk past them to the other shore', 'He was testing whether they would call out', 'He did not see them in the darkness', 'a', 'Mark 6:48 — "And he saw them toiling in rowing... and about the fourth watch of the night he cometh unto them, walking upon the sea, and would have passed by them." This echoes God''s self-revelation in the OT.'),
('Mark', 6, 'adults', 8, 'What does Mark say was the reason the disciples were amazed at the walking on water and their hearts were hardened?', 'They considered not the miracle of the loaves — they failed to understand what the feeding miracle revealed about Jesus'' identity', 'They were naturally afraid of the dark', 'They had never seen the sea before', 'They were exhausted from rowing', 'a', 'Mark 6:52 — "For they considered not the miracle of the loaves: for their heart was hardened."');

-- ═══ Mark Chapter 7 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 7, 'kids', 1, 'What did Jesus say makes a person unclean?', 'Evil things that come out from within a person''s heart', 'Not washing hands before eating', 'Touching dirty animals', 'Eating the wrong food', 'a', 'Mark 7:20-21 — "That which cometh out of the man, that defileth the man. For from within, out of the heart of men, proceed evil thoughts."'),
('Mark', 7, 'kids', 2, 'What did the woman from Syrophoenicia ask Jesus to do?', 'Cast the devil out of her daughter', 'Heal her own sickness', 'Give her food to eat', 'Teach her to pray', 'a', 'Mark 7:26 — "The woman was a Greek, a Syrophenician by nation; and she besought him that he would cast forth the devil out of her daughter."'),
('Mark', 7, 'kids', 3, 'What did Jesus use to heal the deaf man?', 'He put His fingers in the man''s ears and touched his tongue', 'He gave him medicine', 'He told him to wash in a river', 'He placed a cloth on his head', 'a', 'Mark 7:33 — "And he took him aside from the multitude, and put his fingers into his ears, and he spit, and touched his tongue."'),
-- Teens
('Mark', 7, 'teens', 1, 'What did the Pharisees and scribes criticize the disciples for?', 'Eating bread with unwashed (defiled) hands, not following the tradition of the elders', 'Not attending the synagogue', 'Not paying the temple tax', 'Not wearing proper clothing', 'a', 'Mark 7:2,5 — "They saw some of his disciples eat bread with defiled, that is to say, with unwashen, hands... Why walk not thy disciples according to the tradition of the elders?"'),
('Mark', 7, 'teens', 2, 'What Old Testament prophet did Jesus quote against the Pharisees?', 'Isaiah — "This people honoureth me with their lips, but their heart is far from me"', 'Jeremiah — "The heart is deceitful above all things"', 'Ezekiel — "I will give them a new heart"', 'Amos — "Let justice roll down like waters"', 'a', 'Mark 7:6 — "Well hath Esaias prophesied of you hypocrites, as it is written, This people honoureth me with their lips, but their heart is far from me."'),
('Mark', 7, 'teens', 3, 'What practice of the Pharisees did Jesus condemn as "Corban"?', 'Declaring money as a gift devoted to God to avoid supporting their parents', 'Giving extra offerings to the temple', 'Fasting twice a week for God', 'Teaching children the Law of Moses', 'a', 'Mark 7:11-12 — "If a man shall say to his father or mother, It is Corban, that is to say, a gift, by whatsoever thou mightest be profited by me... ye suffer him no more to do ought for his father or his mother."'),
('Mark', 7, 'teens', 4, 'How did the Syrophoenician woman respond to Jesus'' statement about the children''s bread?', 'Yes, Lord: yet the dogs under the table eat of the children''s crumbs', 'She walked away in anger', 'She demanded equal treatment', 'She offered to pay for the healing', 'a', 'Mark 7:28 — "And she answered and said unto him, Yes, Lord: yet the dogs under the table eat of the children''s crumbs."'),
('Mark', 7, 'teens', 5, 'What word did Jesus say when healing the deaf man, and what does it mean?', 'Ephphatha, which means Be opened', 'Talitha cumi, which means Arise', 'Eloi, which means My God', 'Hosanna, which means Save us', 'a', 'Mark 7:34 — "And looking up to heaven, he sighed, and saith unto him, Ephphatha, that is, Be opened."'),
-- Adults
('Mark', 7, 'adults', 1, 'What does Jesus'' teaching in verses 18-19 declare about all foods?', 'That nothing from outside entering a man can defile him — Mark notes this purges (cleanses) all meats', 'That only kosher foods are acceptable', 'That fasting is required before eating', 'That vegetarianism is the Christian ideal', 'a', 'Mark 7:18-19 — "Whatsoever thing from without entereth into the man, it cannot defile him... purging all meats."'),
('Mark', 7, 'adults', 2, 'What thirteen evil things does Jesus list as coming from within the heart of man?', 'Evil thoughts, adulteries, fornications, murders, thefts, covetousness, wickedness, deceit, lasciviousness, an evil eye, blasphemy, pride, foolishness', 'Only hatred and jealousy', 'Poverty, illness, and bad luck', 'Ignorance, laziness, and poor hygiene', 'a', 'Mark 7:21-22 — "For from within, out of the heart of men, proceed evil thoughts, adulteries, fornications, murders, Thefts, covetousness, wickedness, deceit, lasciviousness, an evil eye, blasphemy, pride, foolishness."'),
('Mark', 7, 'adults', 3, 'How does Jesus'' accusation in verse 8 distinguish between divine law and human tradition?', 'He says the Pharisees lay aside the commandment of God to hold the tradition of men', 'He says human tradition is more important', 'He says both are equally authoritative', 'He abolishes all law entirely', 'a', 'Mark 7:8 — "For laying aside the commandment of God, ye hold the tradition of men."'),
('Mark', 7, 'adults', 4, 'What does the "Corban" controversy in verses 10-13 reveal about the danger of religious tradition?', 'Human traditions, even religious ones, can be used to circumvent God''s moral commands — here, the fifth commandment to honour parents', 'That all religious traditions are inherently evil', 'That the Pharisees had good intentions', 'That financial offerings replace moral duties', 'a', 'Mark 7:10-13 — Jesus shows that "Corban" vows were used to evade the commandment "Honour thy father and thy mother," making God''s word of no effect through tradition.'),
('Mark', 7, 'adults', 5, 'What is the theological significance of Jesus healing the Syrophoenician woman''s daughter?', 'It demonstrates that God''s grace extends beyond Israel to the Gentiles — the gospel is for all nations', 'That Gentiles must earn their healing', 'That Jesus only helped non-Jews reluctantly', 'That Jewish priority in salvation is permanent', 'a', 'Mark 7:29-30 — "For this saying go thy way; the devil is gone out of thy daughter." Jesus healed a Gentile''s child, foreshadowing the gospel going to all nations.'),
('Mark', 7, 'adults', 6, 'In what region did Jesus heal the deaf man with a speech impediment?', 'Decapolis — a Gentile region of ten cities', 'Jerusalem — the holy city', 'Nazareth — His hometown', 'Bethlehem — the city of David', 'a', 'Mark 7:31 — "And again, departing from the coasts of Tyre and Sidon, he came unto the sea of Galilee, through the midst of the coasts of Decapolis."'),
('Mark', 7, 'adults', 7, 'What is notable about Jesus'' method of healing the deaf man (fingers in ears, spitting, touching tongue)?', 'Jesus used physical actions to communicate with a man who could not hear verbal commands, accommodating his disability', 'Jesus needed physical contact for all healings', 'Saliva was considered medicine in the first century', 'It was a ritual required by Mosaic law', 'a', 'Mark 7:33-35 — Jesus adapted His approach to reach a man who could not hear. The physical touch communicated what words could not.'),
('Mark', 7, 'adults', 8, 'What did the people say after the healing of the deaf man, echoing Genesis and Isaiah?', 'He hath done all things well: he maketh both the deaf to hear, and the dumb to speak', 'He is merely a good teacher', 'He has power from Beelzebub', 'He is the reincarnation of Elijah', 'a', 'Mark 7:37 — "He hath done all things well: he maketh both the deaf to hear, and the dumb to speak." This echoes Genesis 1:31 ("very good") and Isaiah 35:5-6.');

-- ═══ Mark Chapter 8 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Mark', 8, 'kids', 1, 'How many loaves did Jesus use to feed four thousand people?', 'Seven', 'Five', 'Three', 'Twelve', 'a', 'Mark 8:5-6 — "And he asked them, How many loaves have ye? And they said, Seven... and he took the seven loaves."'),
('Mark', 8, 'kids', 2, 'What did Peter say when Jesus asked who the disciples thought He was?', 'Thou art the Christ', 'You are a great teacher', 'You are John the Baptist', 'You are Elijah', 'a', 'Mark 8:29 — "And Peter answereth and saith unto him, Thou art the Christ."'),
('Mark', 8, 'kids', 3, 'What did Jesus say a person must do to follow Him?', 'Deny himself, take up his cross, and follow Me', 'Give all his money away', 'Move to Jerusalem', 'Study for many years', 'a', 'Mark 8:34 — "Whosoever will come after me, let him deny himself, and take up his cross, and follow me."'),
-- Teens
('Mark', 8, 'teens', 1, 'How many baskets of leftovers were collected after the feeding of the four thousand?', 'Seven baskets', 'Twelve baskets', 'Five baskets', 'Three baskets', 'a', 'Mark 8:8 — "So they did eat, and were filled: and they took up of the broken meat that was left seven baskets."'),
('Mark', 8, 'teens', 2, 'What did the Pharisees demand from Jesus that He refused to give?', 'A sign from heaven', 'Tax money', 'A public apology', 'A written letter', 'a', 'Mark 8:11-12 — "And the Pharisees came forth, and began to question with him, seeking of him a sign from heaven... There shall no sign be given unto this generation."'),
('Mark', 8, 'teens', 3, 'What did Jesus warn the disciples to beware of?', 'The leaven of the Pharisees and the leaven of Herod', 'The soldiers of Rome', 'The storms on the sea', 'The wild animals in the desert', 'a', 'Mark 8:15 — "And he charged them, saying, Take heed, beware of the leaven of the Pharisees, and of the leaven of Herod."'),
('Mark', 8, 'teens', 4, 'What did the blind man at Bethsaida see at first after Jesus touched him?', 'Men as trees, walking — his sight was only partially restored at first', 'Nothing at all', 'Perfect clear vision immediately', 'Only bright light', 'a', 'Mark 8:24 — "And he looked up, and said, I see men as trees, walking."'),
('Mark', 8, 'teens', 5, 'What did Jesus say would happen to someone who is ashamed of Him?', 'The Son of man shall be ashamed of him when He comes in the glory of His Father with the holy angels', 'Nothing will happen', 'They will be forgiven later', 'They will receive a second chance', 'a', 'Mark 8:38 — "Whosoever therefore shall be ashamed of me and of my words... of him also shall the Son of man be ashamed, when he cometh in the glory of his Father with the holy angels."'),
-- Adults
('Mark', 8, 'adults', 1, 'What is the significance of Jesus'' two feeding miracles — five thousand (ch. 6) and four thousand (ch. 8)?', 'The 5,000 with 12 baskets left symbolizes ministry to Israel (12 tribes); the 4,000 with 7 baskets symbolizes ministry to Gentiles (7 representing completeness)', 'They are the same event told twice', 'Jesus only fed Jews in both cases', 'The numbers are symbolic of zodiac signs', 'a', 'Mark 8:19-20 — Jesus specifically asks the disciples to recall both miracles and the different numbers of baskets (12 and 7), suggesting distinct theological significance.'),
('Mark', 8, 'adults', 2, 'What did Jesus mean by "the leaven of the Pharisees and Herod"?', 'Their hypocritical teaching and corrupt influence that spreads like yeast through dough', 'Literal bread and yeast', 'Their baking traditions', 'Their dietary restrictions', 'a', 'Mark 8:15 — "Beware of the leaven of the Pharisees, and of the leaven of Herod." Leaven symbolizes corrupting influence; the Pharisees'' legalism and Herod''s worldliness both distort truth.'),
('Mark', 8, 'adults', 3, 'Why is the two-stage healing of the blind man at Bethsaida unique among Jesus'' miracles?', 'It is the only recorded miracle where Jesus healed in two stages, likely illustrating the disciples'' own partial understanding that needed further enlightenment', 'Jesus'' power was weakened that day', 'The man''s blindness was too severe for one touch', 'It was a failed first attempt', 'a', 'Mark 8:23-25 — The progressive healing mirrors the disciples'' own journey from spiritual blindness to partial sight (Peter''s confession) to full understanding (after the resurrection).'),
('Mark', 8, 'adults', 4, 'What did people say about who Jesus was when He asked the disciples?', 'John the Baptist, Elias (Elijah), or one of the prophets', 'The Son of David, a king, or the Messiah', 'Moses, Abraham, or Solomon', 'An angel, a priest, or a scribe', 'a', 'Mark 8:28 — "And they answered, John the Baptist: but some say, Elias; and others, One of the prophets."'),
('Mark', 8, 'adults', 5, 'What did Jesus begin to teach the disciples after Peter''s confession?', 'That the Son of man must suffer many things, be rejected, be killed, and after three days rise again', 'That they should go to Rome and preach', 'That the kingdom would come immediately', 'That they should establish a political movement', 'a', 'Mark 8:31 — "And he began to teach them, that the Son of man must suffer many things, and be rejected of the elders, and of the chief priests, and scribes, and be killed, and after three days rise again."'),
('Mark', 8, 'adults', 6, 'How did Jesus respond when Peter rebuked Him for predicting His suffering?', 'Get thee behind me, Satan: for thou savourest not the things that be of God, but the things that be of men', 'Thank you, Peter, for your concern', 'I will reconsider my path', 'You may be right about this', 'a', 'Mark 8:33 — "But when he had turned about and looked on his disciples, he rebuked Peter, saying, Get thee behind me, Satan: for thou savourest not the things that be of God, but the things that be of men."'),
('Mark', 8, 'adults', 7, 'What rhetorical question does Jesus ask about the value of a soul?', 'What shall it profit a man, if he shall gain the whole world, and lose his own soul?', 'How much gold is a man''s life worth?', 'What shall a man give in exchange for his freedom?', 'Who can measure the value of wisdom?', 'a', 'Mark 8:36 — "For what shall it profit a man, if he shall gain the whole world, and lose his own soul?"'),
('Mark', 8, 'adults', 8, 'How does Peter''s confession in Mark 8:29 serve as the structural pivot of Mark''s Gospel?', 'It marks the transition from the first half (who is Jesus? — revealed through miracles) to the second half (what must Jesus do? — the way of the cross)', 'It is merely one of many confessions in the book', 'It represents the end of Jesus'' ministry', 'It has no special literary significance', 'a', 'Mark 8:29 — "Thou art the Christ." This confession divides Mark: chapters 1-8 reveal Jesus'' identity; chapters 9-16 reveal His mission of suffering, death, and resurrection.');
